# push-claimcenter.ps1
# Creates all ClaimCenter automation files and pushes to GitHub.
# Run from an empty folder, e.g. C:\ClaimCenter-Automation

Set-StrictMode -Off
$ErrorActionPreference = 'Stop'

Write-Host ''
Write-Host '=================================================' -ForegroundColor Cyan
Write-Host '  ClaimCenter Automation - Create and Push' -ForegroundColor Cyan
Write-Host '=================================================' -ForegroundColor Cyan
Write-Host ''

if (-not (Test-Path 'fixtures')) { New-Item -ItemType Directory -Path 'fixtures' -Force | Out-Null }
if (-not (Test-Path 'helpers')) { New-Item -ItemType Directory -Path 'helpers' -Force | Out-Null }
if (-not (Test-Path 'reporters')) { New-Item -ItemType Directory -Path 'reporters' -Force | Out-Null }
if (-not (Test-Path 'tests')) { New-Item -ItemType Directory -Path 'tests' -Force | Out-Null }
if (-not (Test-Path 'tests\ApprovalRouting')) { New-Item -ItemType Directory -Path 'tests\ApprovalRouting' -Force | Out-Null }
if (-not (Test-Path 'tests\FNOL')) { New-Item -ItemType Directory -Path 'tests\FNOL' -Force | Out-Null }
if (-not (Test-Path 'tests\Financials')) { New-Item -ItemType Directory -Path 'tests\Financials' -Force | Out-Null }

$b64_playwright_config_js = ''
$bytes_playwright_config_js = [System.Convert]::FromBase64String($b64_playwright_config_js)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'playwright.config.js'), $bytes_playwright_config_js)
Write-Host '   Written: playwright.config.js' -ForegroundColor Green

$b64_package_json = ''
$bytes_package_json = [System.Convert]::FromBase64String($b64_package_json)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'package.json'), $bytes_package_json)
Write-Host '   Written: package.json' -ForegroundColor Green

$b64_helpers_claimLifecycleHelper_js = ''
$bytes_helpers_claimLifecycleHelper_js = [System.Convert]::FromBase64String($b64_helpers_claimLifecycleHelper_js)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'helpers/claimLifecycleHelper.js'), $bytes_helpers_claimLifecycleHelper_js)
Write-Host '   Written: helpers/claimLifecycleHelper.js' -ForegroundColor Green

$b64_helpers_fnolHelper_js = ''
$bytes_helpers_fnolHelper_js = [System.Convert]::FromBase64String($b64_helpers_fnolHelper_js)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'helpers/fnolHelper.js'), $bytes_helpers_fnolHelper_js)
Write-Host '   Written: helpers/fnolHelper.js' -ForegroundColor Green

$b64_helpers_claimCenterBase_js = ''
$bytes_helpers_claimCenterBase_js = [System.Convert]::FromBase64String($b64_helpers_claimCenterBase_js)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'helpers/claimCenterBase.js'), $bytes_helpers_claimCenterBase_js)
Write-Host '   Written: helpers/claimCenterBase.js' -ForegroundColor Green

$b64_helpers_financialsHelper_js = ''
$bytes_helpers_financialsHelper_js = [System.Convert]::FromBase64String($b64_helpers_financialsHelper_js)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'helpers/financialsHelper.js'), $bytes_helpers_financialsHelper_js)
Write-Host '   Written: helpers/financialsHelper.js' -ForegroundColor Green

$b64_helpers_approvalRoutingHelper_js = ''
$bytes_helpers_approvalRoutingHelper_js = [System.Convert]::FromBase64String($b64_helpers_approvalRoutingHelper_js)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'helpers/approvalRoutingHelper.js'), $bytes_helpers_approvalRoutingHelper_js)
Write-Host '   Written: helpers/approvalRoutingHelper.js' -ForegroundColor Green

$b64_reporters_tcResultReporter_js = ''
$bytes_reporters_tcResultReporter_js = [System.Convert]::FromBase64String($b64_reporters_tcResultReporter_js)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'reporters/tcResultReporter.js'), $bytes_reporters_tcResultReporter_js)
Write-Host '   Written: reporters/tcResultReporter.js' -ForegroundColor Green

$b64_reporters_generateExcelReport_js = ''
$bytes_reporters_generateExcelReport_js = [System.Convert]::FromBase64String($b64_reporters_generateExcelReport_js)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'reporters/generateExcelReport.js'), $bytes_reporters_generateExcelReport_js)
Write-Host '   Written: reporters/generateExcelReport.js' -ForegroundColor Green

$b64_fixtures_testData_js = ''
$bytes_fixtures_testData_js = [System.Convert]::FromBase64String($b64_fixtures_testData_js)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'fixtures/testData.js'), $bytes_fixtures_testData_js)
Write-Host '   Written: fixtures/testData.js' -ForegroundColor Green

$b64_tests_ClaimLifecycle_test_js = ''
$bytes_tests_ClaimLifecycle_test_js = [System.Convert]::FromBase64String($b64_tests_ClaimLifecycle_test_js)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'tests/ClaimLifecycle.test.js'), $bytes_tests_ClaimLifecycle_test_js)
Write-Host '   Written: tests/ClaimLifecycle.test.js' -ForegroundColor Green

$b64_tests_ApprovalRouting_ApprovalRouting_test_js = ''
$bytes_tests_ApprovalRouting_ApprovalRouting_test_js = [System.Convert]::FromBase64String($b64_tests_ApprovalRouting_ApprovalRouting_test_js)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'tests/ApprovalRouting/ApprovalRouting.test.js'), $bytes_tests_ApprovalRouting_ApprovalRouting_test_js)
Write-Host '   Written: tests/ApprovalRouting/ApprovalRouting.test.js' -ForegroundColor Green

$b64_tests_FNOL_FNOL_test_js = ''
$bytes_tests_FNOL_FNOL_test_js = [System.Convert]::FromBase64String($b64_tests_FNOL_FNOL_test_js)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'tests/FNOL/FNOL.test.js'), $bytes_tests_FNOL_FNOL_test_js)
Write-Host '   Written: tests/FNOL/FNOL.test.js' -ForegroundColor Green

$b64_tests_Financials_Financials_test_js = ''
$bytes_tests_Financials_Financials_test_js = [System.Convert]::FromBase64String($b64_tests_Financials_Financials_test_js)
[System.IO.File]::WriteAllBytes((Join-Path $PWD 'tests/Financials/Financials.test.js'), $bytes_tests_Financials_Financials_test_js)
Write-Host '   Written: tests/Financials/Financials.test.js' -ForegroundColor Green

$gitignore = "node_modules/`ntest-results/`nplaywright-report/`nresults/`n*.log`n.env`n.env.local`n.DS_Store`nThumbds.db"
[System.IO.File]::WriteAllText((Join-Path $PWD '.gitignore'), $gitignore, [System.Text.Encoding]::UTF8)
Write-Host '   Written: .gitignore' -ForegroundColor Green

$envex = "# Copy to .env and fill in real values`n# NEVER commit .env`n`nCC_BASE_URL=https://your-tenant.guidewire.com/cc/`nCC_USER=your_username`nCC_PASS=your_password`n`n# Policy numbers per LOB x State`nPOLICY_PA_AUTO=XXXX-000001`nPOLICY_MI_AUTO=XXXX-000002`nPOLICY_HO_PA=XXXX-000003`nPOLICY_HO_VA=XXXX-000004`nPOLICY_WC_PA=XXXX-000005`nPOLICY_WC_MI=XXXX-000006`nPOLICY_BOP_PA=XXXX-000007`nPOLICY_BOP_DE=XXXX-000008`nPOLICY_CP_PA=XXXX-000009`nPOLICY_CP_MI=XXXX-000010`nPOLICY_CAU_PA=XXXX-000011`nPOLICY_CAU_MI=XXXX-000012"
[System.IO.File]::WriteAllText((Join-Path $PWD '.env.example'), $envex, [System.Text.Encoding]::UTF8)
Write-Host '   Written: .env.example' -ForegroundColor Green


if (-not (Test-Path '.git')) { git init; Write-Host 'Git initialized' -ForegroundColor Green }

git add .
git commit -m "Initial commit - ClaimCenter Playwright automation framework

- 5 helpers: claimCenterBase, fnolHelper, financialsHelper, approvalRoutingHelper, claimLifecycleHelper
- 4 test suites: FNOL (14 LOBs), Financials (43 TCs), ApprovalRouting (34 DMAR rules), ClaimLifecycle
- 2 reporters: tcResultReporter.js, generateExcelReport.js (7-sheet Excel)
- 80 TCs covering 165 Gosu rules across 4 feature areas"

$remotes = git remote 2>$null
if ($remotes -notcontains 'origin') {
    git remote add origin https://github.com/amitmish0041/ClaimCenter-Automation.git
}
git branch -M main
git push -u origin main

if ($LASTEXITCODE -eq 0) {
    Write-Host ''
    Write-Host '=================================================' -ForegroundColor Green
    Write-Host '  SUCCESS - pushed to GitHub!' -ForegroundColor Green
    Write-Host '=================================================' -ForegroundColor Green
    Write-Host '  https://github.com/amitmish0041/ClaimCenter-Automation' -ForegroundColor Cyan
    Write-Host ''
    Write-Host '  Next steps:' -ForegroundColor Cyan
    Write-Host '  1. npm install'
    Write-Host '  2. npx playwright install chromium'
    Write-Host '  3. Copy .env.example to .env and add CC credentials + policy numbers'
    Write-Host '  4. npm run test:fnol'
    Write-Host '  5. npm run excel   (generate Excel after run)'
} else {
    Write-Host 'Push failed. Try: git push -u origin main' -ForegroundColor Red
}
